"""Caching feature: caches rendered page content to disk."""
import json
import os
import time

from features.shared import format_timestamp, hash_key, sanitize_path


class PageCache:
    """Disk-backed page cache with TTL expiration."""

    def __init__(self, config):
        self.config = config
        self.cache_dir = config.cache_dir
        self.ttl = config.cache_ttl
        self.max_size = config.cache_max_size
        self._hits = 0
        self._misses = 0

    def _cache_path(self, path):
        """Generate the filesystem path for a cached page."""
        key = hash_key(path)
        return os.path.join(self.cache_dir, f"{key}.json")

    def get(self, path):
        """Retrieve a cached page, or None if miss/expired."""
        cache_file = self._cache_path(path)
        if not os.path.exists(cache_file):
            self._misses += 1
            return None

        try:
            with open(cache_file, "r") as f:
                entry = json.load(f)
        except (json.JSONDecodeError, OSError):
            self._misses += 1
            return None

        if time.time() - entry.get("created_at", 0) > self.ttl:
            self._evict(cache_file)
            self._misses += 1
            return None

        self._hits += 1
        return entry["content"]

    def put(self, path, content):
        """Store rendered page content in the cache."""
        self._ensure_cache_dir()
        self._enforce_max_size()

        cache_file = self._cache_path(path)
        now = time.time()
        entry = {
            "path": path,
            "content": content,
            "created_at": now,
            "created_fmt": format_timestamp(now),
            "key": hash_key(path),
        }
        with open(cache_file, "w") as f:
            json.dump(entry, f)

        return entry["key"]

    def invalidate(self, path):
        """Remove a specific page from the cache."""
        cache_file = self._cache_path(path)
        self._evict(cache_file)

    def clear(self):
        """Remove all cached entries."""
        if os.path.exists(self.cache_dir):
            for fname in os.listdir(self.cache_dir):
                if fname.endswith(".json"):
                    os.remove(os.path.join(self.cache_dir, fname))

    def get_stats(self):
        """Return cache hit/miss statistics."""
        total = self._hits + self._misses
        rate = (self._hits / total * 100) if total > 0 else 0.0
        return {
            "hits": self._hits,
            "misses": self._misses,
            "hit_rate": round(rate, 1),
            "cached_pages": self._count_entries(),
        }

    def _ensure_cache_dir(self):
        os.makedirs(self.cache_dir, exist_ok=True)

    def _evict(self, cache_file):
        if os.path.exists(cache_file):
            os.remove(cache_file)

    def _enforce_max_size(self):
        if self._count_entries() >= self.max_size:
            self._evict_oldest()

    def _count_entries(self):
        if not os.path.exists(self.cache_dir):
            return 0
        return len([f for f in os.listdir(self.cache_dir) if f.endswith(".json")])

    def _evict_oldest(self):
        """Remove the oldest cache entry."""
        if not os.path.exists(self.cache_dir):
            return
        oldest_file = None
        oldest_time = float("inf")
        for fname in os.listdir(self.cache_dir):
            if fname.endswith(".json"):
                fpath = os.path.join(self.cache_dir, fname)
                mtime = os.path.getmtime(fpath)
                if mtime < oldest_time:
                    oldest_time = mtime
                    oldest_file = fpath
        if oldest_file:
            os.remove(oldest_file)

