"""Rate limiting feature: tracks request counts per IP."""
import time
from collections import defaultdict

from features.shared import hash_key


class RateLimiter:
    """Sliding-window rate limiter based on IP address."""

    def __init__(self, config):
        self.config = config
        self.window = config.rate_limit_window
        self.max_requests = config.rate_limit_max_requests
        self.ban_duration = config.rate_limit_ban_duration
        self._requests = defaultdict(list)  # hashed_ip -> [timestamps]
        self._bans = {}  # hashed_ip -> ban_expires_at

    def check_rate_limit(self, ip_address):
        """Check if an IP is within rate limits.

        Returns (allowed: bool, info: dict)
        """
        ip_key = hash_key(ip_address)
        now = time.time()

        # Check if IP is banned
        if ip_key in self._bans:
            if now < self._bans[ip_key]:
                remaining = self._bans[ip_key] - now
                return False, {
                    "reason": "banned",
                    "retry_after": round(remaining),
                    "ip_hash": ip_key,
                }
            else:
                del self._bans[ip_key]

        # Clean old entries outside the window
        window_start = now - self.window
        self._requests[ip_key] = [
            ts for ts in self._requests[ip_key] if ts > window_start
        ]

        # Check rate
        request_count = len(self._requests[ip_key])
        if request_count >= self.max_requests:
            self._bans[ip_key] = now + self.ban_duration
            return False, {
                "reason": "rate_exceeded",
                "limit": self.max_requests,
                "window": self.window,
                "ip_hash": ip_key,
            }

        # Allow and record
        self._requests[ip_key].append(now)
        return True, {
            "remaining": self.max_requests - request_count - 1,
            "window": self.window,
            "ip_hash": ip_key,
        }

    def get_request_count(self, ip_address):
        """Get current request count for an IP within the window."""
        ip_key = hash_key(ip_address)
        now = time.time()
        window_start = now - self.window
        self._requests[ip_key] = [
            ts for ts in self._requests[ip_key] if ts > window_start
        ]
        return len(self._requests[ip_key])

    def is_banned(self, ip_address):
        """Check if an IP is currently banned."""
        ip_key = hash_key(ip_address)
        if ip_key not in self._bans:
            return False
        if time.time() >= self._bans[ip_key]:
            del self._bans[ip_key]
            return False
        return True

    def unban(self, ip_address):
        """Manually remove a ban on an IP."""
        ip_key = hash_key(ip_address)
        if ip_key in self._bans:
            del self._bans[ip_key]
            return True
        return False

    def get_stats(self):
        """Return rate limiter statistics."""
        now = time.time()
        active_ips = sum(
            1
            for timestamps in self._requests.values()
            if any(ts > now - self.window for ts in timestamps)
        )
        active_bans = sum(1 for exp in self._bans.values() if exp > now)
        return {
            "active_ips": active_ips,
            "active_bans": active_bans,
            "total_tracked": len(self._requests),
        }

