"""Main web application with feature-flagged analytics, caching, and rate limiting."""
import json
import time

from config import config
from features import AnalyticsTracker, PageCache, RateLimiter
from features.shared import format_timestamp, sanitize_path


class WebApp:
    """Simple web application framework with pluggable features."""

    def __init__(self, app_config=None):
        self.config = app_config or config
        self.routes = {}
        self._request_count = 0
        self._started_at = time.time()

        # Initialize features based on flags
        self.analytics = None
        self.cache = None
        self.rate_limiter = None

        if self.config.analytics_enabled:
            self.analytics = AnalyticsTracker(self.config)

        if self.config.caching_enabled:
            self.cache = PageCache(self.config)

        if self.config.rate_limiting_enabled:
            self.rate_limiter = RateLimiter(self.config)

    def route(self, path):
        """Decorator to register a route handler."""
        def decorator(func):
            self.routes[path] = func
            return func
        return decorator

    def handle_request(self, method, path, ip_address="127.0.0.1",
                       headers=None, body=None):
        """Process an incoming HTTP request through the feature pipeline."""
        headers = headers or {}
        self._request_count += 1

        # --- Rate limiting check ---
        if self.config.rate_limiting_enabled and self.rate_limiter:
            allowed, info = self.rate_limiter.check_rate_limit(ip_address)
            if not allowed:
                return self._make_response(
                    429, {"error": "Rate limit exceeded", "details": info}
                )

        # --- Analytics: track page view ---
        if self.config.analytics_enabled and self.analytics:
            user_agent = headers.get("User-Agent")
            self.analytics.track_page_view(path, ip_address, user_agent)
            # Track session if session cookie is present
            session_id = headers.get("X-Session-ID")
            if session_id:
                self.analytics.track_session(session_id, {"last_path": path})

        # --- Cache check (only for GET requests) ---
        if method == "GET" and self.config.caching_enabled and self.cache:
            cached = self.cache.get(path)
            if cached is not None:
                # Even on cache hit, analytics was already tracked above
                return self._make_response(200, cached, from_cache=True)

        # --- Route handler ---
        handler = self.routes.get(path)
        if handler is None:
            return self._make_response(404, {"error": "Not found"})

        try:
            result = handler(method=method, path=path, headers=headers, body=body)
        except Exception as e:
            return self._make_response(500, {"error": str(e)})

        # --- Cache the response (only for GET) ---
        if method == "GET" and self.config.caching_enabled and self.cache:
            self.cache.put(path, result)

        return self._make_response(200, result)

    def get_status(self):
        """Return application status including all feature stats."""
        status = {
            "app": self.config.app_name,
            "uptime": round(time.time() - self._started_at, 1),
            "total_requests": self._request_count,
            "active_features": self.config.get_active_features(),
            "started_at": format_timestamp(self._started_at),
        }

        # Gather stats from active features
        if self.config.analytics_enabled and self.analytics:
            status["analytics"] = self.analytics.get_stats()

        if self.config.caching_enabled and self.cache:
            status["caching"] = self.cache.get_stats()

        if self.config.rate_limiting_enabled and self.rate_limiter:
            status["rate_limiting"] = self.rate_limiter.get_stats()

        return status

    def get_combined_report(self):
        """Generate a combined report when analytics and caching are both active.

        This report cross-references analytics page view data with cache hit rates
        to identify pages that are frequently viewed but rarely cached.
        """
        report = {"generated_at": format_timestamp()}

        if self.config.analytics_enabled and self.config.caching_enabled:
            if self.analytics and self.cache:
                top_pages = self.analytics.get_top_pages(5)
                cache_stats = self.cache.get_stats()
                report["top_pages_vs_cache"] = {
                    "top_pages": top_pages,
                    "cache_hit_rate": cache_stats["hit_rate"],
                    "recommendation": "Consider pre-warming cache for top pages"
                    if cache_stats["hit_rate"] < 50
                    else "Cache performance is good",
                }

        if self.config.rate_limiting_enabled and self.rate_limiter:
            report["rate_limiting"] = self.rate_limiter.get_stats()

        return report

    def _make_response(self, status_code, body, from_cache=False):
        """Create a standardized response dict."""
        resp = {
            "status": status_code,
            "body": body,
            "timestamp": format_timestamp(),
        }
        if from_cache:
            resp["x-cache"] = "HIT"
        return resp


def create_app(app_config=None):
    """Factory function to create and configure the app with default routes."""
    app = WebApp(app_config)

    @app.route("/")
    def index(method, path, headers, body):
        return {"message": "Welcome", "features": config.get_active_features()}

    @app.route("/status")
    def status(method, path, headers, body):
        return app.get_status()

    @app.route("/report")
    def report(method, path, headers, body):
        return app.get_combined_report()

    return app
